"use client";

import React from "react";
import * as katex from "katex";

export type PeriodicDeepTopic = "map" | "radius" | "ionization" | "electronGain" | "electronegativity" | "zeff" | "chemistry" | "special" | "families" | "dblock";

type Block =
  | { kind: "section" | "heading" | "subheading" | "paragraph" | "formula"; value: string }
  | { kind: "list" | "ordered"; value: string[] }
  | { kind: "table"; value: string[][] };

const MARKER = "periodicity-generated-corpus-v10-cleaned";

function renderMath(tex: string, displayMode: boolean): string {
  try {
    return katex.renderToString(tex, {
      throwOnError: false,
      displayMode,
      output: "htmlAndMathml",
      strict: "warn",
      trust: false,
    });
  } catch {
    return tex;
  }
}

function Inline({ text }: { text: string }) {
  const parts = text.split(/(\*\*[^*]+\*\*|`[^`]+`|\\\([\s\S]*?\\\))/g);
  return <>{parts.map((part, i) => {
    if (!part) return null;
    if (part.startsWith("**") && part.endsWith("**")) return <strong key={i}>{part.slice(2, -2)}</strong>;
    if (part.startsWith("`") && part.endsWith("`")) return <code key={i} style={{ fontFamily: "ui-monospace, SFMono-Regular, Menlo, monospace", color: "#bdefff" }}>{part.slice(1, -1)}</code>;
    if (part.startsWith("\\(") && part.endsWith("\\)")) {
      const tex = part.slice(2, -2);
      return <span key={i} className="sb-katex-inline" style={{ color: "#9fe6ff" }} dangerouslySetInnerHTML={{ __html: renderMath(tex, false) }} />;
    }
    return <React.Fragment key={i}>{part}</React.Fragment>;
  })}</>;
}

function TableBlock({ rows }: { rows: string[][] }) {
  return (
    <div style={{ overflowX: "auto", margin: "16px 0 22px" }}>
      <table style={{ width: "100%", minWidth: 620, borderCollapse: "collapse", color: "#edf4f8", fontSize: 14 }}>
        <tbody>
          {rows.map((row, r) => (
            <tr key={r}>
              {row.map((cell, c) => {
                const Tag = r === 0 ? "th" : "td";
                return (
                  <Tag key={c} style={{ border: "1px solid #31516f", padding: "10px 12px", textAlign: "left", verticalAlign: "top", background: r === 0 ? "#183149" : r % 2 ? "#102334" : "#0d1d2c" }}>
                    <Inline text={cell} />
                  </Tag>
                );
              })}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default function PeriodicTableDeepAdditions({ topic }: { topic: PeriodicDeepTopic }) {
  const blocks = DATA[topic] ?? [];
  if (!blocks.length) return null;
  return (
    <section data-notes-version={MARKER} data-topic={topic} aria-label="Advanced periodicity notes" style={{ marginTop: 34, borderTop: "1px solid #29445e", paddingTop: 28 }}>
      <div style={{ maxWidth: 1120, margin: "0 auto" }}>
        <p style={{ margin: "0 0 8px", color: "#7fd9b8", fontSize: 12, fontWeight: 800, letterSpacing: ".12em", textTransform: "uppercase" }}>Advanced conceptual extension</p>
        <h2 style={{ margin: "0 0 20px", color: "#f4c95d", fontFamily: "Georgia, serif", fontSize: "clamp(24px, 3vw, 34px)", lineHeight: 1.2 }}>Deeper theory, derivations and applications</h2>
        {blocks.map((block, index) => {
          if (block.kind === "section" || block.kind === "heading") return <h3 key={index} style={{ color: "#dceeff", fontFamily: "Georgia, serif", fontSize: 22, margin: "28px 0 12px", lineHeight: 1.3 }}><Inline text={String(block.value)} /></h3>;
          if (block.kind === "subheading") return <h4 key={index} style={{ color: "#9fdff0", fontSize: 17, margin: "22px 0 9px" }}><Inline text={String(block.value)} /></h4>;
          if (block.kind === "formula") return (
            <div key={index} style={{ overflowX: "auto", margin: "14px 0", padding: "14px 16px", border: "1px solid #31516f", borderRadius: 10, background: "#0d1d2c", color: "#f4f8fb", fontFamily: "Cambria Math, Georgia, serif", fontSize: 17 }}>
              <span className="sb-katex-block" dangerouslySetInnerHTML={{ __html: renderMath(String(block.value), true) }} />
            </div>
          );
          if (block.kind === "list" || block.kind === "ordered") {
            const Tag = block.kind === "ordered" ? "ol" : "ul";
            return <Tag key={index} style={{ margin: "10px 0 16px 24px", color: "#e7eef5", lineHeight: 1.72 }}>{block.value.map((item, j) => <li key={j} style={{ marginBottom: 6 }}><Inline text={item} /></li>)}</Tag>;
          }
          if (block.kind === "table") return <TableBlock key={index} rows={block.value} />;
          return <p key={index} style={{ margin: "0 0 13px", color: "#e7eef5", fontSize: 15.5, lineHeight: 1.76 }}><Inline text={String(block.value)} /></p>;
        })}
      </div>
    </section>
  );
}

